      titleBtns.appendChild(docsBtn);
      title.appendChild(titleBtns);
      top.appendChild(title);

      const cfg = document.createElement('div');
      cfg.style.cssText = `display:grid; gap:6px; font-size:12px; color:${colors.textSecondary};`;
